const request = $input.first().json;
const body = request.body ?? {};
const config = Object.freeze({
  allowedOrigin: 'https://paesegregori.casaortegaimoveis.com.br',
  spreadsheetId: '13y_9C-c3rQ6MYaIxPFOzpivG338EvpjDbF7WbcKY3aM',
  sheetName: 'Página1',
  whatsappRecipient: '5511919890615',
  evolutionBaseUrl: 'https://evo.figueiramarketing.com.br',
  evolutionInstance: 'Guilherme014',
  projectName: 'Nhambí Moema | Carolline'
});

const clean = (value, max = 500) => String(value ?? '').replace(/\s+/g, ' ').trim().slice(0, max);
const parseBoolean = (value) => value === true || String(value ?? '').toLowerCase() === 'true' || String(value ?? '').toLowerCase() === 'sim';
const inferPlatform = (source, medium, fbclid) => {
  const normalizedSource = clean(source, 80).toLowerCase();
  const normalizedMedium = clean(medium, 80).toLowerCase();
  if (/instagram|^ig$/.test(normalizedSource)) return 'instagram';
  if (/facebook|^fb$/.test(normalizedSource)) return 'facebook';
  if (/meta/.test(normalizedSource) || fbclid) return 'meta';
  if (/google|adwords|gads|googleads/.test(normalizedSource)) return /cpc|paid|ppc|ads/.test(normalizedMedium) ? 'google_ads' : 'google';
  if (/youtube/.test(normalizedSource)) return 'youtube';
  if (/tiktok/.test(normalizedSource)) return 'tiktok';
  if (/linkedin/.test(normalizedSource)) return 'linkedin';
  if (normalizedSource) return normalizedSource.replace(/[^a-z0-9_-]/g, '_').slice(0, 50);
  return 'website';
};

const origin = clean(request.headers?.origin, 300);
if (origin !== config.allowedOrigin) throw new Error('Origem não autorizada.');
if (clean(body.website, 200)) throw new Error('Envio bloqueado.');

const eventType = clean(body.event_type || 'lead_form_submit', 80);
const isQualifiedUpdate = eventType === 'qualified_whatsapp_click';
const phone = clean(body.phone, 30);
const phoneDigits = phone.replace(/\D/g, '');
const prazoAquisicao = clean(body.purchase_timeline || body.schedule, 120);
const qualifiedAt = clean(body.qualified_whatsapp_clicked_at, 80);
const utmSource = clean(body.utm_source, 200);
const utmMedium = clean(body.utm_medium, 200);
const fbclid = clean(body.fbclid, 1000);
const platform = clean(body.platform, 50) || inferPlatform(utmSource, utmMedium, fbclid);
const whatsappQualificacao = isQualifiedUpdate
  ? 'QUENTE - clicou no WhatsApp pós-formulário' + (qualifiedAt ? ' em ' + qualifiedAt : '')
  : clean(body.qualified_whatsapp_status, 220) || 'PENDENTE - formulário enviado, ainda não clicou no WhatsApp pós-formulário';

const lead = {
  event_type: eventType,
  is_qualified_update: isQualifiedUpdate,
  id: clean(body.id, 80),
  created_time: new Date().toISOString(),
  ad_id: clean(body.ad_id, 80),
  ad_name: clean(body.ad_name, 200),
  adset_id: clean(body.adset_id, 80),
  adset_name: clean(body.adset_name, 200),
  campaign_id: clean(body.campaign_id, 80),
  campaign_name: clean(body.campaign_name, 200),
  form_id: clean(body.form_id, 80) || 'leadForm',
  form_name: clean(body.form_name, 200) || 'Landing Page | Nhambí Moema | Carolline',
  is_organic: Boolean(body.is_organic),
  platform,
  nome_completo: clean(body.name, 120),
  telefone: phoneDigits,
  email: clean(body.email, 180),
  inbox_url: clean(body.inbox_url, 2000),
  lead_status: 'CREATED',
  interest: clean(body.interest, 80),
  best_contact_time: prazoAquisicao,
  prazo_aquisicao: prazoAquisicao,
  whatsapp_qualificacao: whatsappQualificacao,
  lead_temperature: clean(body.lead_temperature, 40) || (isQualifiedUpdate ? 'hot' : 'warm'),
  qualified_whatsapp_clicked: isQualifiedUpdate || parseBoolean(body.qualified_whatsapp_clicked),
  qualified_whatsapp_clicked_at: qualifiedAt,
  utm_source: utmSource,
  utm_medium: utmMedium,
  utm_campaign: clean(body.utm_campaign, 300),
  utm_content: clean(body.utm_content, 300),
  utm_term: clean(body.utm_term, 300),
  fbclid,
  landing_url: clean(body.landing_url, 2000),
  referrer: clean(body.referrer, 2000),
  telefone_valido: phoneDigits.length >= 10 && phoneDigits.length <= 13,
  config
};

if (!lead.id) throw new Error('Protocolo obrigatório ausente.');
if (!lead.is_qualified_update && (!lead.nome_completo || !lead.telefone || !lead.interest || !lead.prazo_aquisicao)) {
  throw new Error('Campos obrigatórios ausentes.');
}

return [{ json: lead }];

const lead = $('Configurar e Normalizar').item.json;
const rows = $input.first().json.values ?? [];
const rowIndex = rows.findIndex((row) => row?.[0] === lead.id);
if (rowIndex < 0) throw new Error('Protocolo não encontrado na planilha: ' + lead.id);
return [{ json: { ...lead, sheet_row: rowIndex + 1 } }];
